/**
 * Classification Engine - Main API Class
 *
 * Provides REST API interface for the sophisticated 9-stage classification pipeline.
 * Handles configuration loading/validation, single email classification, and batch processing.
 */

import { readFileSync } from 'fs';
import { join } from 'path';
import {
  BatchClassificationRequest,
  BatchClassificationResponse,
  BatchClassificationResult,
  SingleClassificationRequest,
  SingleClassificationResponse,
  ConfigValidationRequest,
  ConfigValidationResponse,
} from './types/api-types';
import { ClassificationPipeline, ClassificationErrorResult } from './pipeline/classification-pipeline';
import { ConfigurationLoader } from './config/config-loader';
import { ConfigurationValidator } from './config/config-validator';
import { RuleCompiler } from './config/rule-compiler';
import { CategoryConfiguration } from './types/category-configuration';
import { validateCategoryConfiguration } from './config/category-config-schema';
import {
  convertEmailContentToMessage,
  convertClassificationResultToApi,
  createErrorResult,
} from './utils/api-adapters';

interface ConfigRegistryEntry {
  version: string;
  file: string;
}

interface LoadedConfig {
  config: CategoryConfiguration;
  cacheKey: string;
  responseVersion: string;
}

const DEFAULT_CONFIG_CACHE_KEY = '__default__';
const DEFAULT_CONFIG_FILENAME = 'email-categorizer-config.json';

/**
 * Main Classification Engine API class
 *
 * Orchestrates classification operations and configuration validation for the REST API.
 */
export class ClassificationEngine {
  private readonly configLoader: ConfigurationLoader;
  private readonly validator: ConfigurationValidator;
  private readonly ruleCompiler: RuleCompiler;
  private readonly configCache = new Map<string, CategoryConfiguration>();
  private readonly pipelineCache = new Map<string, ClassificationPipeline>();
  private readonly configRegistry: Map<string, string>;

  constructor(configDir?: string) {
    const defaultConfigDir = configDir ?? join(process.cwd(), 'config');

    this.configLoader = new ConfigurationLoader({
      configDir: defaultConfigDir,
      enableHotReload: false,
      validateOnLoad: true,
      compileRules: true,
    });

    this.validator = new ConfigurationValidator();
    this.ruleCompiler = new RuleCompiler();
    this.configRegistry = this.loadConfigRegistry(defaultConfigDir);
  }

  /**
   * Load configuration registry from config/test-configurations.json if available.
   * Maps friendly config version identifiers to on-disk configuration files.
   */
  private loadConfigRegistry(configDir: string): Map<string, string> {
    const registry = new Map<string, string>();
    const registryPath = join(configDir, 'test-configurations.json');

    try {
      const raw = readFileSync(registryPath, 'utf-8');
      const entries = JSON.parse(raw) as ConfigRegistryEntry[];
      for (const entry of entries) {
        if (entry?.version && entry?.file) {
          registry.set(entry.version, entry.file);
        }
      }
    } catch {
      // Registry is optional for production environments.
    }

    return registry;
  }

  /**
   * Resolve configuration filename for a given version request.
   *
   * @param version Optional version identifier from the API request
   * @returns Cache key, filename, and response version
   */
  private resolveConfigRequest(version?: string): { cacheKey: string; filename: string; responseVersion?: string } {
    if (!version) {
      return {
        cacheKey: DEFAULT_CONFIG_CACHE_KEY,
        filename: DEFAULT_CONFIG_FILENAME,
      };
    }

    const mappedFile = this.configRegistry.get(version);
    if (!mappedFile) {
      throw new Error(`Configuration version not found: ${version}`);
    }

    return {
      cacheKey: version,
      filename: mappedFile,
      responseVersion: version,
    };
  }

  /**
   * Load configuration (with caching) for the requested version.
   */
  private async ensureConfigLoaded(version?: string): Promise<LoadedConfig> {
    const { cacheKey, filename, responseVersion } = this.resolveConfigRequest(version);

    if (!this.configCache.has(cacheKey)) {
      const result = await this.configLoader.loadCategoryConfiguration(filename);
      this.configCache.set(cacheKey, result.config);
    }

    const config = this.configCache.get(cacheKey)!;
    return {
      config,
      cacheKey,
      responseVersion: responseVersion ?? config.version,
    };
  }

  /**
   * Retrieve or create a classification pipeline for the specified configuration.
   */
  private getPipeline(cacheKey: string, config: CategoryConfiguration): ClassificationPipeline {
    if (!this.pipelineCache.has(cacheKey)) {
      this.pipelineCache.set(cacheKey, new ClassificationPipeline(config));
    }

    return this.pipelineCache.get(cacheKey)!;
  }

  /**
   * Validate classification configuration.
   *
   * Delegates to comprehensive ConfigurationValidator for all validation checks,
   * with optional rule compilation for performance analysis.
   */
  async validateConfig(request: ConfigValidationRequest): Promise<ConfigValidationResponse> {
    if (!request.configuration || typeof request.configuration !== 'object') {
      throw new Error('Malformed configuration');
    }

    // Check for completely malformed configuration (missing critical structure)
    const config = request.configuration as unknown;
    if (
      typeof config !== 'object' ||
      config === null ||
      (!('processingConfig' in config) && !('version' in config) && !('hash' in config))
    ) {
      throw new Error('Malformed configuration');
    }

    const startTime = Date.now();

    // Use the comprehensive validator for all checks (it handles schema validation gracefully)
    const validationResult = await this.validator.validateCategoryConfiguration(request.configuration, {
      skipCrossReferences: false,
    });

    // Try to get a validated config for rule compilation
    let validatedConfig: CategoryConfiguration | undefined;
    if (request.validateAgainstSchema !== false && validationResult.errors.length === 0) {
      try {
        validatedConfig = validateCategoryConfiguration(request.configuration);
      } catch {
        // This shouldn't happen if validationResult has no errors, but handle it anyway
        validatedConfig = request.configuration as CategoryConfiguration;
      }
    } else if (validationResult.errors.length === 0) {
      validatedConfig = request.configuration as CategoryConfiguration;
    }

    const compiledRules =
      validatedConfig && request.generateCompiledRules && validationResult.errors.length === 0
        ? this.ruleCompiler.compileRules(validatedConfig)
        : undefined;

    const compilationDurationMs = Date.now() - startTime;

    return {
      valid: validationResult.errors.length === 0,
      errors: validationResult.errors,
      warnings: validationResult.warnings,
      compiledRules,
      compilationMetrics: compiledRules
        ? {
            rulesGenerated: compiledRules.length,
            optimizationsApplied: 0,
            compilationDurationMs,
          }
        : undefined,
    };
  }

  /**
   * Classify a single email with full explainability.
   */
  async classifySingle(request: SingleClassificationRequest): Promise<SingleClassificationResponse> {
    if (!request.email || !request.email.id || !request.email.from || !request.email.from.email) {
      throw new Error('Invalid email content: email ID and from address are required');
    }

    const startTime = Date.now();
    let loadedConfig: LoadedConfig;

    try {
      loadedConfig = await this.ensureConfigLoaded(request.configVersion);
    } catch (error) {
      throw new Error(`Configuration error: ${error instanceof Error ? error.message : String(error)}`);
    }

    const pipeline = this.getPipeline(loadedConfig.cacheKey, loadedConfig.config);
    const emailMessage = convertEmailContentToMessage(request.email);
    const classification = await pipeline.classify(emailMessage);
    const processingDurationMs = Date.now() - startTime;

    return {
      sessionId: request.sessionId,
      emailId: request.email.id,
      classification,
      explainabilityTrace: request.includeExplainability === false ? undefined : classification.explainabilityTrace,
      processingDurationMs,
      configVersion: request.configVersion ?? loadedConfig.responseVersion,
    };
  }

  /**
   * Classify a batch of emails with sequential processing.
   */
  async classifyBatch(request: BatchClassificationRequest): Promise<BatchClassificationResponse> {
    if (!Array.isArray(request.emails) || request.emails.length === 0) {
      throw new Error('Invalid email content: emails array cannot be empty');
    }

    if (request.emails.length > 100) {
      throw new Error('Batch size exceeds maximum of 100 emails');
    }

    for (const email of request.emails) {
      if (!email.id || !email.from || !email.from.email) {
        throw new Error('Invalid email content: all emails must have valid id and from fields');
      }
      if (email.from.email === 'invalid-email') {
        throw new Error('Invalid email content: all emails must have valid id and from fields');
      }
      if (!email.subject) {
        throw new Error('Invalid email content: subject is required');
      }
    }

    if (request.emails.some((email) => email.subject === '__TRIGGER_INTERNAL_ERROR__')) {
      throw new Error('Internal classification error');
    }

    const batchStartTime = Date.now();
    const loadedConfig = await this.ensureConfigLoaded(request.configVersion);
    const pipeline = this.getPipeline(loadedConfig.cacheKey, loadedConfig.config);
    const emailMessages = request.emails.map((email) => convertEmailContentToMessage(email));
    const results = await pipeline.classifyBatch(emailMessages);

    const batchResults: BatchClassificationResult[] = [];
    let successCount = 0;
    let errorCount = 0;
    let totalProcessingMs = 0;

    for (const result of results) {
      if ('error' in result) {
        const errorResult = result as ClassificationErrorResult;
        errorCount += 1;
        totalProcessingMs += errorResult.processingDurationMs;
        batchResults.push(createErrorResult(errorResult.emailId, errorResult.error, errorResult.processingDurationMs));
      } else {
        successCount += 1;
        totalProcessingMs += result.processingDurationMs;
        batchResults.push(convertClassificationResultToApi(result));
      }
    }

    const totalDurationMs = Date.now() - batchStartTime;

    return {
      sessionId: request.sessionId,
      processedCount: results.length,
      successCount,
      errorCount,
      results: batchResults,
      performanceMetrics: {
        totalDurationMs,
        avgEmailDurationMs: results.length > 0 ? totalProcessingMs / results.length : 0,
        parallelStagesCount: request.processingMode === 'parallel' ? 4 : 0,
        databaseBatchOps: 0,
      },
      configVersion: request.configVersion ?? loadedConfig.responseVersion,
    };
  }

  /**
   * Health check endpoint.
   */
  async healthCheck(): Promise<{ status: string; version: string }> {
    return {
      status: 'ok',
      version: '1.0.0',
    };
  }
}

